<script lang="ts">
  import { onMount } from 'svelte';
  import { parseLinkInput, filterLinks, allTags } from '../launchpad/links';
  import { faviconUrl, reorderLinks, toggleLinkFlag } from '../launchpad/actions';
  import { PersistentCollection } from '../storage/persistent';
  import type { LaunchpadLink } from '../storage/models';
  export let projectId = 'default'; export let initialLinks: LaunchpadLink[] = []; export let onChange: (links: LaunchpadLink[]) => void = () => undefined;
  const persisted = new PersistentCollection('launchpad_links'); let links: LaunchpadLink[] = initialLinks; let url = ''; let title = ''; let tags = ''; let query = ''; let selectedTag = ''; let error = ''; let dragged = -1; let editing: LaunchpadLink | undefined;
  $: visibleLinks = filterLinks(links, query, selectedTag || undefined); $: tagsList = allTags(links); $: orderedLinks = [...links].sort((a, b) => Number(b.pinned) - Number(a.pinned) || (a.position ?? 0) - (b.position ?? 0));
  onMount(async () => { try { links = await persisted.load(projectId); } catch { links = initialLinks; } });
  function notify(): void { links = links.map((link, index) => ({ ...link, position: index })); onChange(links); }
  async function addLink(): Promise<void> { try { const input = parseLinkInput(url, title, tags, projectId); const saved = await persisted.create({ ...input, blurred: false, pinned: false, position: links.length }); links = [saved, ...links]; onChange(links); url = ''; title = ''; tags = ''; error = ''; } catch (cause) { error = cause instanceof Error ? cause.message : 'Unable to add link'; } }
  async function remove(link: LaunchpadLink): Promise<void> { await persisted.softDelete(link.id); links = links.filter((item) => item.id !== link.id); onChange(links); }
  async function toggle(link: LaunchpadLink, flag: 'blurred' | 'pinned'): Promise<void> { const updated = await persisted.update(toggleLinkFlag(link, flag)); links = links.map((item) => item.id === link.id ? updated : item); if (flag === 'pinned') notify(); onChange(links); }
  async function saveEdit(): Promise<void> { if (!editing) return; try { const input = parseLinkInput(editing.url, editing.title, editing.tags?.join(',') ?? '', editing.project_id); const updated = await persisted.update({ ...editing, ...input }); links = links.map((item) => item.id === updated.id ? updated : item); editing = undefined; onChange(links); } catch (cause) { error = cause instanceof Error ? cause.message : 'Unable to edit link'; } }
  async function drop(target: number): Promise<void> { if (dragged < 0 || dragged === target) return; links = reorderLinks(links, dragged, target); dragged = -1; notify(); for (const [position, link] of links.entries()) await persisted.update({ ...link, position }); }
</script>
<div class="launchpad-view" aria-label="Launchpad"><div class="launchpad-toolbar"><div><p class="eyebrow">Quick access</p><h4>Launchpad</h4></div><input aria-label="Search links" bind:value={query} placeholder="Search links…" /></div><form class="link-form" on:submit|preventDefault={addLink}><input aria-label="Link URL" bind:value={url} placeholder="https://example.com" /><input aria-label="Link title" bind:value={title} placeholder="Title" /><input aria-label="Link tags" bind:value={tags} placeholder="Tags" /><button type="submit">Add link</button></form>{#if error}<p class="error">{error}</p>{/if}{#if tagsList.length}<div class="tag-row"><button on:click={() => selectedTag = ''}>All</button>{#each tagsList as tag}<button on:click={() => selectedTag = tag}>#{tag}</button>{/each}</div>{#if orderedLinks.filter((link) => link.pinned).length}<section class="pinned-section"><h5>Pinned</h5><div class="link-grid">{#each orderedLinks.filter((link) => link.pinned) as link, index (link.id)}<article class:blurred={link.blurred} class="link-tile" draggable="true" on:dragstart={() => dragged = index} on:dragover|preventDefault on:drop={() => drop(index)}><a href={link.url} target="_blank" rel="noreferrer"><img class="favicon" src={faviconUrl(link.url)} alt="" on:error={(event) => (event.currentTarget as HTMLImageElement).src = '/icons/blank/empty.svg'} /><span><strong>{link.title}</strong><small>{new URL(link.url).hostname}</small></span></a><div class="card-actions"><button aria-label="Toggle blur" on:click={() => toggle(link, 'blurred')}><img src={`/tmp-icons/${link.blurred ? 'obfuscated' : 'obfuscation'}.svg`} alt="" /></button><button aria-label={link.pinned ? 'Unpin link' : 'Pin link'} on:click={() => toggle(link, 'pinned')}>{link.pinned ? '★' : '☆'}</button><button aria-label="Edit link" on:click={() => editing = { ...link }}>✎</button><button aria-label="Delete link" on:click={() => remove(link)}>×</button></div></article>{/each}</div></section>{/if}{#if orderedLinks.filter((link) => !link.pinned).length}<section class="other-section"><h5>Other links</h5><div class="link-grid">{#each orderedLinks.filter((link) => !link.pinned) as link, index (link.id)}<article class:blurred={link.blurred} class="link-tile" draggable="true" on:dragstart={() => dragged = index} on:dragover|preventDefault on:drop={() => drop(index)}><a href={link.url} target="_blank" rel="noreferrer"><img class="favicon" src={faviconUrl(link.url)} alt="" on:error={(event) => (event.currentTarget as HTMLImageElement).src = '/icons/blank/empty.svg'} /><span><strong>{link.title}</strong><small>{new URL(link.url).hostname}</small></span></a><div class="card-actions"><button aria-label="Toggle blur" on:click={() => toggle(link, 'blurred')}><img src={`/tmp-icons/${link.blurred ? 'obfuscated' : 'obfuscation'}.svg`} alt="" /></button><button aria-label={link.pinned ? 'Unpin link' : 'Pin link'} on:click={() => toggle(link, 'pinned')}>{link.pinned ? '★' : '☆'}</button><button aria-label="Edit link" on:click={() => editing = { ...link }}>✎</button><button aria-label="Delete link" on:click={() => remove(link)}>×</button></div></article>{/each}</div></section>{/if}{#if editing}<div class="edit-overlay"><form on:submit|preventDefault={saveEdit}><h4>Edit link</h4><input aria-label="Edit link title" bind:value={editing.title} /><input aria-label="Edit link URL" bind:value={editing.url} /><input aria-label="Edit link tags" value={editing.tags?.join(', ') ?? ''} on:input={(event) => editing = { ...editing, tags: (event.currentTarget as HTMLInputElement).value.split(',').map((tag) => tag.trim()).filter(Boolean) }} /><div><button type="button" on:click={() => editing = undefined}>Cancel</button><button type="submit">Save</button></div></form></div>{/if}{/if}</div>
<style>.launchpad-view { padding: .25rem 0; } .launchpad-toolbar, .link-form, .tag-row, .link-tile a { display: flex; align-items: center; } .launchpad-toolbar { justify-content: space-between; margin-bottom: 1rem; } .eyebrow { margin: 0; color: var(--text-muted); font-size: .68rem; text-transform: uppercase; } h4 { margin: .2rem 0 0; } input { min-width: 0; padding: .6rem; border: 1px solid var(--border-custom); border-radius: .4rem; background: var(--bg-elevated); color: var(--text-main); } .launchpad-toolbar input { width: 18rem; } .link-form { gap: .4rem; } .link-form input { flex: 1; } button { padding: .55rem .7rem; border: 1px solid var(--border-custom); border-radius: .4rem; background: var(--accent-primary); color: var(--text-inverse); cursor: pointer; } .tag-row { gap: .3rem; margin: .8rem 0; } .tag-row button { padding: .3rem .5rem; background: var(--bg-elevated); color: var(--text-muted); font-size: .7rem; } .link-grid { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: .75rem; } .link-tile { position: relative; min-height: 6.5rem; padding: .85rem; border: 1px solid var(--border-custom); border-radius: .65rem; background: var(--bg-elevated); } .link-tile a { gap: .65rem; color: var(--text-main); text-decoration: none; } .favicon { width: 2rem; height: 2rem; border-radius: .5rem; } .link-tile span { display: grid; gap: .2rem; min-width: 0; } strong, small { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; } small { color: var(--text-muted); font-size: .7rem; } .card-actions { position: absolute; right: .45rem; bottom: .4rem; display: flex; gap: .15rem; opacity: 0; } .link-tile:hover .card-actions, .card-actions:focus-within { opacity: 1; } .card-actions button { padding: .2rem .3rem; border: 0; background: transparent; color: var(--text-muted); } .blurred strong, .blurred small { filter: blur(var(--blur-intensity)); } .error { color: #c84d5d; font-size: .75rem; } .edit-overlay { position: fixed; z-index: 30; inset: 0; display: grid; place-items: center; background: rgb(0 0 0 / .5); } .edit-overlay form { display: grid; gap: .7rem; width: min(30rem, calc(100vw - 2rem)); padding: 1.2rem; border: 1px solid var(--border-custom); border-radius: .6rem; background: var(--bg-primary); } .edit-overlay form div { display: flex; justify-content: flex-end; gap: .4rem; } @media (max-width: 1100px) { .link-grid { grid-template-columns: repeat(3, minmax(0, 1fr)); } } @media (max-width: 720px) { .link-form, .launchpad-toolbar { align-items: stretch; flex-direction: column; } .launchpad-toolbar input { width: 100%; } .link-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); } }</style>
